-- ============================================================
-- Dr. Marvin question_bank seed
-- Source: 01_DOCS/dr-marvin/DR_MARVIN_KNOWLEDGE_BASE.md
-- Generated: 2026-06-02
--
-- Notes:
--   - Seed only. Requires public.question_bank to exist.
--   - Uses seven canonical system_category values from AGENTS.md task.
--   - All questions use frequency scoring: 0 / 1 / 2.
-- ============================================================

do $$
begin
  if to_regclass('public.question_bank') is null then
    raise exception 'public.question_bank does not exist. Run supabase/dr_marvin_question_engine.sql before this seed.';
  end if;

  alter table public.question_bank
    add column if not exists created_at timestamptz not null default now(),
    add column if not exists updated_at timestamptz not null default now(),
    add column if not exists is_active boolean not null default true;

  if not exists (
    select 1
    from pg_constraint
    where conname = 'question_bank_unique_question'
      and conrelid = 'public.question_bank'::regclass
  ) then
    alter table public.question_bank
      add constraint question_bank_unique_question
      unique (system_category, age_groups, gender_filter, question_text);
  end if;
end $$;

on conflict on constraint question_bank_unique_question do update set
  question_type = excluded.question_type,
  options = excluded.options,
  weight = excluded.weight,
  priority = excluded.priority,
  is_active = true,
  updated_at = now();

